// Field definitions for admin UI.
// These describe how to render fields for each entity type.
// The generated admin-registry.ts provides CRUD metadata;
// this file provides per-field display and form configuration.
//
// This file can be:
//   1. Generated by ontogen as a baseline (recommended)
//   2. Hand-maintained for full control
//   3. Extended via admin-fields.overrides.ts in the consuming app

export type FieldType =
  | 'string'
  | 'text'
  | 'number'
  | 'boolean'
  | 'enum'
  | 'string-array'
  | 'relation'
  | 'relation-array'

export interface AdminFieldDef {
  key: string
  label: string
  type: FieldType
  required?: boolean
  /** For 'enum' fields */
  enumValues?: string[]
  /** For 'relation' / 'relation-array' fields — target entity key */
  relationTo?: string
  /** Show in list table columns */
  showInTable?: boolean
  /** Show in detail view */
  showInDetail?: boolean
  /** Show in create/edit form */
  showInForm?: boolean
  /** Is this the primary ID field (not editable on update) */
  isId?: boolean
  /** Render as markdown body */
  isBody?: boolean
  /** Read-only (e.g. source_file) */
  readOnly?: boolean
}

// Re-exported so consuming apps and the layer itself can import types from here.
// The actual field definitions are expected to be provided by the consuming app
// via a generated or hand-maintained file that populates this record.
//
// Consuming apps should create their own admin-fields.ts that imports and
// re-exports from here, adding their entity-specific field definitions.

/**
 * Registry of field definitions keyed by entity key.
 * Populated by the consuming app (typically via ontogen generation).
 * The layer reads this at runtime via auto-imported composable.
 */
export const adminFieldDefs: Record<string, AdminFieldDef[]> = {}
